import scala.collection.mutable.PriorityQueue
import scala.collection.mutable.ListBuffer

def solve(grid: Array[Array[Long]], k: Long): Long = {
  val m = grid.length
  val n = grid(0).length
  val INF = Long.MaxValue
  val teleportList = Array.ofDim[(Int, Int)](m, n)

  for (i <- 0 until m) {
    for (j <- 0 until n) {
      val currentVal = grid(i)(j)
      val list = ListBuffer[(Int, Int)]()
      for (x <- 0 until m) {
        for (y <- 0 until n) {
          if (grid(x)(y) <= currentVal) {
            list += (x, y)
          }
        }
      }
      teleportList(i)(j) = list.toArray
    }
  }

  val dist = Array.ofDim[Long](m, n, k.toInt + 1)
  for (i <- 0 until m) {
    for (j <- 0 until n) {
      for (t <- 0 until k.toInt + 1) {
        dist(i)(j)(t) = INF
      }
    }
  }
  dist(0)(0)(0) = 0L

  val pq = PriorityQueue[(Long, Int, Int, Int)]()
  pq += (0L, 0, 0, 0)

  while (pq.nonEmpty) {
    val (currentCost, i, j, t) = pq.pop()
    if (i == m - 1 && j == n - 1) return currentCost
    if (currentCost > dist(i)(j)(t)) continue

    // Regular moves
    if (j + 1 < n) {
      val newCost = currentCost + grid(i)(j + 1)
      if (newCost < dist(i)(j + 1)(t)) {
        dist(i)(j + 1)(t) = newCost
        pq += (newCost, i, j + 1, t)
      }
    }
    if (i + 1 < m) {
      val newCost = currentCost + grid(i + 1)(j)
      if (newCost < dist(i + 1)(j)(t)) {
        dist(i + 1)(j)(t) = newCost
        pq += (newCost, i + 1, j, t)
      }
    }

    // Teleportation
    if (t < k.toInt) {
      for ((x, y) <- teleportList(i)(j)) {
        if (currentCost < dist(x)(y)(t + 1)) {
          dist(x)(y)(t + 1) = currentCost
          pq += (currentCost, x, y, t + 1)
        }
      }
    }
  }

  INF
}
